/**
 *
 * @param instanceMap
 * @param event
 * @constructor
 */
export function ChartBrushListener(instanceMap, event) {
    let eventManager = this,
        eventHandler = this.chart.eventHandler;
    if(!(eventHandler.activeBrushComponent === null)){
        eventHandler.activeBrushComponent = "plot";
    }
    let data = eventManager.getData(instanceMap, event.type, event.selection),
        point = data.point;

    // fire the start event
    // if data fire
    if (event.type === 'start' || point.x || point.y) {
        eventManager.associateBehaviours(instanceMap, event.type, data, event.selection, event);
    }
}
